/**
 * Product Media API Client
 * Manual client for product media endpoints (not auto-generated by Orval)
 */
import { customInstance } from '@/api/orval-mutator';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';

// Types
export interface ProductMedia {
  id: string;
  inventoryId: string;
  mediaType: string;
  url: string;
  s3Key?: string;
  filename?: string;
  mimeType?: string;
  fileSize?: number;
  width?: number;
  height?: number;
  sortOrder: number;
  isPrimary: boolean;
  altText?: string;
  source: string;
  sourceId?: string;
  marketplaceCompatibility?: string;
  createdAt?: string;
  updatedAt?: string;
}

export interface ProductMediaCreate {
  mediaType?: string;
  url: string;
  s3Key?: string;
  filename?: string;
  mimeType?: string;
  fileSize?: number;
  width?: number;
  height?: number;
  isPrimary?: boolean;
  altText?: string;
  source?: string;
  sourceId?: string;
}

export interface PresignedUrlResponse {
  url: string;
  fields?: Record<string, string>;
  s3Key: string;
}

// API functions
export const listProductMedia = (inventoryId: string) =>
  customInstance<{ data: ProductMedia[] }>({ url: `/api/inventory/${inventoryId}/media`, method: 'GET' });

export const createProductMedia = (inventoryId: string, data: ProductMediaCreate) =>
  customInstance<{ data: ProductMedia }>({ url: `/api/inventory/${inventoryId}/media`, method: 'POST', data });

export const getPresignedUrl = (inventoryId: string, data: { filename: string; contentType?: string }) =>
  customInstance<{ data: PresignedUrlResponse }>({ url: `/api/inventory/${inventoryId}/media/presigned`, method: 'POST', data });

export const updateProductMedia = (inventoryId: string, mediaId: string, data: { altText?: string; isPrimary?: boolean; sortOrder?: number }) =>
  customInstance<{ data: ProductMedia }>({ url: `/api/inventory/${inventoryId}/media/${mediaId}`, method: 'PUT', data });

export const deleteProductMedia = (inventoryId: string, mediaId: string) =>
  customInstance<{ success: boolean }>({ url: `/api/inventory/${inventoryId}/media/${mediaId}`, method: 'DELETE' });

export const reorderProductMedia = (inventoryId: string, mediaIds: string[]) =>
  customInstance<{ success: boolean }>({ url: `/api/inventory/${inventoryId}/media/reorder`, method: 'POST', data: { mediaIds } });

// Query keys
export const getProductMediaQueryKey = (inventoryId: string) => ['product-media', inventoryId];

// React Query hooks
export function useListProductMedia(inventoryId: string) {
  return useQuery({
    queryKey: getProductMediaQueryKey(inventoryId),
    queryFn: () => listProductMedia(inventoryId),
    enabled: !!inventoryId,
  });
}

export function useCreateProductMedia(inventoryId: string) {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: (data: ProductMediaCreate) => createProductMedia(inventoryId, data),
    onSuccess: () => queryClient.invalidateQueries({ queryKey: getProductMediaQueryKey(inventoryId) }),
  });
}

export function useDeleteProductMedia(inventoryId: string) {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: (mediaId: string) => deleteProductMedia(inventoryId, mediaId),
    onSuccess: () => queryClient.invalidateQueries({ queryKey: getProductMediaQueryKey(inventoryId) }),
  });
}

export function useReorderProductMedia(inventoryId: string) {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: (mediaIds: string[]) => reorderProductMedia(inventoryId, mediaIds),
    onSuccess: () => queryClient.invalidateQueries({ queryKey: getProductMediaQueryKey(inventoryId) }),
  });
}
